import{_ as o,o as a,c as e,a2 as s}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"سیستم ضد یویو (Anti Yo-Yo System)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/advanced/anti-yoyo.md","filePath":"fa/advanced/anti-yoyo.md"}'),i={name:"fa/advanced/anti-yoyo.md"};function r(n,t,c,l,p,d){return a(),e("div",null,[...t[0]||(t[0]=[s('<div dir="rtl"><h1 id="سیستم-ضد-یویو-anti-yo-yo-system" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> سیستم ضد یویو (Anti Yo-Yo System) <a class="header-anchor" href="#سیستم-ضد-یویو-anti-yo-yo-system" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; سیستم ضد یویو (Anti Yo-Yo System)&quot;">​</a></h1><p>یکی از آزاردهنده‌ترین مشکلات در سیستم‌های مقیاس‌بندی پویا، <strong>اثر یویو (Yo-Yo Effect)</strong> (یا پینگ پنگ کیفیت) است.</p><h2 id="مشکل-اصلی" tabindex="-1"><i class="ph ph-warning-circle"></i> مشکل اصلی <a class="header-anchor" href="#مشکل-اصلی" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; مشکل اصلی&quot;">​</a></h2><p>بدون کنترل هوشمند، سیستم در یک حلقه بی‌نهایت گیر می‌افتد:<br> ۱. یک صحنه سنگین باعث افت FPS می‌شود.<br> ۲. افزونه کیفیت گرافیک را کاهش می‌دهد (مثلاً وضوح را کم می‌کند).<br> ۳. بار کاری کاهش می‌یابد و FPS به بالای خط پایه (Baseline) می‌رسد.<br> ۴. افزونه متوجه می‌شود که حاشیه عملکرد (Performance Headroom) دارد و کیفیت گرافیک را به حداکثر بازمی‌گرداند.<br> ۵. FPS دوباره افت می‌کند. این چرخه تکرار می‌شود.</p><p>در نتیجه، بازیکن دچار چشمک‌زدن مداوم کیفیت (Quality flickering) می‌شود. سایه‌ها دائماً ظاهر و ناپدید می‌شوند و تصویر هر ثانیه تار و واضح می‌شود.</p><h2 id="راه‌حل-webap-جریمه-penalty-lockout" tabindex="-1"><i class="ph ph-shield-check"></i> راه‌حل WebAP: جریمه (Penalty Lockout) <a class="header-anchor" href="#راه‌حل-webap-جریمه-penalty-lockout" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; راه‌حل WebAP: جریمه (Penalty Lockout)&quot;">​</a></h2><p>ما با پیاده‌سازی مفهوم Penalty Lockout که بر اساس دو پارامتر در تنظیمات افزونه ساخته شده است، این مشکل را به‌طور کامل ریشه‌کن کرده‌ایم.</p><p>اگر افزونه کیفیت گرافیک را <em>افزایش</em> دهد، یک تایمر پنهان — <strong>Detection Window</strong> (مثلاً ۱۵ ثانیه) — شروع به کار می‌کند. در طول این دوره، Indexer به‌دقت پایداری فریم را زیر نظر می‌گیرد.</p><p>اگر FPS در طول این پنجره زمانی به‌طور ناگهانی افت کند، سیستم یک نتیجه‌گیری قطعی می‌کند: <em>«بهبود گرافیک قبلی یک اشتباه بود. دستگاه نمی‌تواند این سطح را در درازمدت حفظ کند.»</em></p><p><strong>جریمه اعمال می‌شود:</strong><br> ۱. افزونه بلافاصله کیفیت را دوباره کاهش می‌دهد.<br> ۲. یک <strong>Penalty Lockout Duration</strong> سخت‌گیرانه (مثلاً ۶۰ ثانیه) اعمال می‌شود.<br> ۳. برای این یک دقیقه، سیستم <strong>به‌طور قطع از تلاش برای افزایش کیفیت گرافیک منع می‌شود</strong>، حتی اگر FPS بالا برود و پردازنده بیکار شود.</p><div class="tip custom-block"><p class="custom-block-title">قفل جلسه (Session Lock)</p><p>اگر دینامیک بازی شما دارای امواج افزایش بار است و ترجیح می‌دهید پس از اولین افت، کیفیت هرگز بازنگردد، می‌توانید مقدار بسیار بزرگی (مثلاً <code>600</code> برای ۱۰ دقیقه یا <code>3600</code> برای یک ساعت) در فیلد <strong>Penalty Lockout Duration</strong> وارد کنید. این کار به‌طور مؤثری گرافیک را در یک سطح پایین ثابت تا پایان جلسه بازی قفل می‌کند.</p></div><div class="info custom-block"><p class="custom-block-title">اولویت روانی (Fluency Priority)</p><p>این جریمه فقط و فقط تلاش‌ها برای بهبود رندرینگ را مسدود می‌کند. اگر بازیکن وارد صحنه بسیار سنگین‌تری شود و FPS به زیر آستانه بحرانی سقوط کند، افزونه هنوز هم می‌تواند در مواقع اضطراری کیفیت را کاهش دهد. سیستم همیشه روان بودن گیم‌پلی را بر جلوه‌های بصری ترجیح می‌دهد.</p></div></div>',1)])])}const m=o(i,[["render",r]]);export{u as __pageData,m as default};
